+func thumbInlineName(data []byte) string {
+	if isGIFData(data) {
+		return "thumb.gif"
+	}
+	if isPNGData(data) {
+		return "thumb.png"
+	}
+	if isJPEGData(data) {
+		return "thumb.jpg"
+	}
+	return "thumb.bin"
+}
+
+func thumbDims(data []byte, res model.Result) (int, int) {
+	if isGIFData(data) {
+		if len(data) < 10 {
+			return 0, 0
+		}
+		w := int(binary.LittleEndian.Uint16(data[6:8]))
+		h := int(binary.LittleEndian.Uint16(data[8:10]))
+		return w, h
+	}
+	if isPNGData(data) {
+		if len(data) < 24 {
+			return 0, 0
+		}
+		w := int(binary.BigEndian.Uint32(data[16:20]))
+		h := int(binary.BigEndian.Uint32(data[20:24]))
+		return w, h
+	}
+	if res.Width > 0 && res.Height > 0 {
+		return res.Width, res.Height
+	}
+	return 0, 0
+}
+
+func isGIFData(data []byte) bool {
+	if len(data) < 6 {
+		return false
+	}
+	hdr := string(data[:6])
+	return hdr == "GIF87a" || hdr == "GIF89a"
+}
+
+func isPNGData(data []byte) bool {
+	if len(data) < 8 {
+		return false
+	}
+	return data[0] == 0x89 && data[1] == 0x50 && data[2] == 0x4e && data[3] == 0x47 &&
+		data[4] == 0x0d && data[5] == 0x0a && data[6] == 0x1a && data[7] == 0x0a
+}
+
+func isJPEGData(data []byte) bool {
+	return len(data) >= 3 && data[0] == 0xff && data[1] == 0xd8 && data[2] == 0xff
+}
+
+func isSupportedItermImage(data []byte) bool {
+	return isGIFData(data) || isPNGData(data) || isJPEGData(data)
+}
+
+func truncateText(s string, width int) string {
+	if width <= 0 {
+		return s
+	}
+	r := []rune(s)
+	if len(r) <= width {
+		return s
+	}
+	if width <= 1 {
+		return "…"
+	}
+	return string(r[:width-1]) + "…"
+}
+
+func wrapText(s string, width int) []string {
+	if width <= 0 || s == "" {
+		return []string{s}
+	}
+	var out []string
+	r := []rune(s)
+	for len(r) > 0 {
+		n := width
+		if n > len(r) {
+			n = len(r)
+		}
+		out = append(out, string(r[:n]))
+		r = r[n:]
+	}
+	return out
+}

